export interface EpisodeAssistantMessage {
	role: "assistant";
	content: ReadonlyArray<EpisodeAssistantPart>;
}

export interface EpisodeToolResultMessage {
	role: "toolResult";
	toolName: string;
	isError?: boolean;
	content: ReadonlyArray<EpisodeTextPart | { type: string; [key: string]: unknown }>;
}

export interface EpisodeOtherMessage {
	role: string;
	[key: string]: unknown;
}

export type EpisodeMessage = EpisodeAssistantMessage | EpisodeToolResultMessage | EpisodeOtherMessage;

function compactWhitespace(text: string): string {
	return text.replace(/\s+/g, " ").trim();
}

function extractPathArg(args: Record<string, unknown>): string {
	const pathValue = args.file_path ?? args.path;
	return typeof pathValue === "string" ? pathValue : "";
}

function summarizeToolCall(name: string, args: Record<string, unknown>): string {
	switch (name) {
		case "bash": {
			const command = typeof args.command === "string" ? args.command : "";
			const compact = compactWhitespace(command);
			const preview = compact.length > 120 ? `${compact.slice(0, 120)}...` : compact;
			return `$ ${preview}`;
		}
		case "read": {
			const filePath = extractPathArg(args);
			const offset = typeof args.offset === "number" ? args.offset : undefined;
			const limit = typeof args.limit === "number" ? args.limit : undefined;
			if (!filePath) return "read";
			if (offset === undefined && limit === undefined) return `read ${filePath}`;
			const start = offset ?? 1;
			const end = limit !== undefined ? start + limit - 1 : undefined;
			return end !== undefined ? `read ${filePath}:${start}-${end}` : `read ${filePath}:${start}`;
		}
		case "write": {
			const filePath = extractPathArg(args);
			if (!filePath) return "write";
			const content = typeof args.content === "string" ? args.content : "";
			const lineCount = content.length === 0 ? 0 : content.split("\n").length;
			return `write ${filePath} (${lineCount} lines)`;
		}
		case "edit": {
			const filePath = extractPathArg(args);
			return filePath ? `edit ${filePath}` : "edit";
		}
		default: {
			const json = JSON.stringify(args);
			const preview = json.length > 100 ? `${json.slice(0, 100)}...` : json;
			return `${name} ${preview}`;
		}
	}
}

function summarizeToolResult(message: EpisodeToolResultMessage): string {
	const textParts = message.content
		.filter((part): part is EpisodeTextPart => part.type === "text" && typeof part.text === "string")
		.map((part) => part.text)
		.map((part) => part.trim())
		.filter((part) => part.length > 0);

	const body = textParts.length > 0 ? compactWhitespace(textParts.join("\n")) : "(no text output)";
	const preview = body.length > 180 ? `${body.slice(0, 180)}...` : body;
	const statusPrefix = message.isError ? "error" : "ok";
	return `${message.toolName} (${statusPrefix}): ${preview}`;
}

/**
 * Build a compact episode transcript from assistant + tool-result messages.
 *
 * The output intentionally keeps:
 * - tool call history,
 * - tool-result summaries, and
 * - the full text from the last assistant response (including multipart text).
 */
export function buildEpisode(messages: ReadonlyArray<EpisodeMessage>): string {
	const sections: string[] = [];
	const toolCalls: string[] = [];
	const toolResults: string[] = [];
	let lastAssistantTextParts: string[] = [];

	for (const message of messages) {
		if (message.role === "assistant") {
			const textParts: string[] = [];

			for (const part of message.content) {
				if (part.type === "toolCall") {
					toolCalls.push(summarizeToolCall(part.name, part.arguments));
					continue;
				}

				if (part.type === "text" && typeof part.text === "string") {
					textParts.push(part.text);
				}
			}

			if (textParts.length > 0) {
				lastAssistantTextParts = textParts;
			}
			continue;
		}

		if (message.role === "toolResult") {
			toolResults.push(summarizeToolResult(message));
		}
	}

	if (toolCalls.length > 0) {
		sections.push("TOOL CALLS:");
		for (const summary of toolCalls) {
			sections.push(`  ${summary}`);
		}
		sections.push("");
	}

	if (toolResults.length > 0) {
		sections.push("TOOL RESULTS:");
		for (const summary of toolResults) {
			sections.push(`  ${summary}`);
		}
		sections.push("");
	}

	if (lastAssistantTextParts.length > 0) {
		sections.push("THREAD RESPONSE:");
		sections.push(...lastAssistantTextParts);
	}

	return sections.join("\n") || "(no output)";
}
"}

