export type QueuedRunState = {
	tag: "queued";
};

export type RunningRunState = {
	tag: "running";
	pid: number;
};

export type TerminatingRunState = {
	tag: "terminating";
	pid: number;
	reason: string;
};

export type ExitedRunState = {
	tag: "exited";
	exitCode: number | null;
	signal: NodeJS.Signals | null;
};

export type RunState = QueuedRunState | RunningRunState | TerminatingRunState | ExitedRunState;

export type StartedRunEvent = {
	type: "started";
	pid: number;
};

export type TerminationRequestedRunEvent = {
	type: "terminationRequested";
	reason: string;
};

export type ExitedRunEvent = {
	type: "exited";
	exitCode: number | null;
	signal: NodeJS.Signals | null;
};

export type RunEvent = StartedRunEvent | TerminationRequestedRunEvent | ExitedRunEvent;

export function transitionRunState(state: QueuedRunState, event: StartedRunEvent): RunningRunState;
export function transitionRunState(state: RunningRunState, event: TerminationRequestedRunEvent): TerminatingRunState;
export function transitionRunState(state: RunningRunState, event: ExitedRunEvent): ExitedRunState;
export function transitionRunState(state: TerminatingRunState, event: ExitedRunEvent): ExitedRunState;
export function transitionRunState(state: RunState, event: RunEvent): RunState {
	if (state.tag === "queued" && event.type === "started") {
		return { tag: "running", pid: event.pid };
	}

	if (state.tag === "running" && event.type === "terminationRequested") {
		return { tag: "terminating", pid: state.pid, reason: event.reason };
	}

	if (state.tag === "running" && event.type === "exited") {
		return { tag: "exited", exitCode: event.exitCode, signal: event.signal };
	}

	if (state.tag === "terminating" && event.type === "exited") {
		return { tag: "exited", exitCode: event.exitCode, signal: event.signal };
	}

	return state;
}

