import type { ChildProcess } from "node:child_process";

export interface TerminateActorProcessOptions {
	sigtermGraceMs: number;
}

interface ExitSnapshot {
	exitCode: number | null;
	exitSignal: NodeJS.Signals | null;
}

export interface TerminateActorProcessResult extends ExitSnapshot {
	/**
	 * True when this function had to escalate to SIGKILL.
	 */
	forced: boolean;
	/**
	 * The final signal this function sent (`SIGTERM`, `SIGKILL`, or `null` when
	 * the process had already exited before termination was requested).
	 */
	signal: "SIGTERM" | "SIGKILL" | null;
}

function getExitSnapshot(child: ChildProcess): ExitSnapshot | null {
	if (child.exitCode === null && child.signalCode === null) return null;
	return {
		exitCode: child.exitCode,
		exitSignal: child.signalCode,
	};
}

function waitForExit(child: ChildProcess): Promise<ExitSnapshot> {
	const exited = getExitSnapshot(child);
	if (exited) return Promise.resolve(exited);

	return new Promise<ExitSnapshot>((resolve) => {
		const onExit = (exitCode: number | null, exitSignal: NodeJS.Signals | null) => {
			cleanup();
			resolve({ exitCode, exitSignal });
		};

		const cleanup = () => {
			child.off("exit", onExit);
		};

		child.once("exit", onExit);

		const racedExit = getExitSnapshot(child);
		if (racedExit) {
			cleanup();
			resolve(racedExit);
		}
	});
}

function waitForExitOrTimeout(child: ChildProcess, timeoutMs: number): Promise<ExitSnapshot | null> {
	const exited = getExitSnapshot(child);
	if (exited) return Promise.resolve(exited);

	return new Promise<ExitSnapshot | null>((resolve) => {
		let settled = false;

		const cleanup = () => {
			clearTimeout(timer);
			child.off("exit", onExit);
		};

		const onExit = (exitCode: number | null, exitSignal: NodeJS.Signals | null) => {
			if (settled) return;
			settled = true;
			cleanup();
			resolve({ exitCode, exitSignal });
		};

		const timer = setTimeout(() => {
			if (settled) return;
			settled = true;
			cleanup();
			resolve(null);
		}, Math.max(0, timeoutMs));

		child.once("exit", onExit);

		const racedExit = getExitSnapshot(child);
		if (racedExit && !settled) {
			settled = true;
			cleanup();
			resolve(racedExit);
		}
	});
}

const PRE_SIGTERM_SETTLE_MS = 25;

/**
 * Gracefully terminate an actor process.
 *
 * Behavior:
 * 1. Allow a tiny startup settle window (for just-spawned processes to install
 *    signal handlers).
 * 2. Send SIGTERM.
 * 3. Wait up to `sigtermGraceMs` for real process exit (via exit code/signal).
 * 4. If still running, escalate to SIGKILL and wait for real exit.
 *
 * Important: this does not use `child.killed` to infer exit.
 */
export async function terminateActorProcess(
	child: ChildProcess,
	{ sigtermGraceMs }: TerminateActorProcessOptions,
): Promise<TerminateActorProcessResult> {
	const exitedBeforeTermination = getExitSnapshot(child);
	if (exitedBeforeTermination) {
		return {
			forced: false,
			signal: null,
			...exitedBeforeTermination,
		};
	}

	const settleMs = Math.min(Math.max(0, sigtermGraceMs), PRE_SIGTERM_SETTLE_MS);
	if (settleMs > 0) {
		const exitedDuringSettle = await waitForExitOrTimeout(child, settleMs);
		if (exitedDuringSettle) {
			return {
				forced: false,
				signal: null,
				...exitedDuringSettle,
			};
		}
	}

	child.kill("SIGTERM");

	const exitedAfterSigterm = await waitForExitOrTimeout(child, sigtermGraceMs);
	if (exitedAfterSigterm) {
		return {
			forced: false,
			signal: "SIGTERM",
			...exitedAfterSigterm,
		};
	}

	const racedExitAfterTimeout = getExitSnapshot(child);
	if (racedExitAfterTimeout) {
		return {
			forced: false,
			signal: "SIGTERM",
			...racedExitAfterTimeout,
		};
	}

	const sentSigkill = child.kill("SIGKILL");
	const finalExit = await waitForExit(child);

	if (sentSigkill) {
		return {
			forced: true,
			signal: "SIGKILL",
			...finalExit,
		};
	}

	return {
		forced: false,
		signal: "SIGTERM",
		...finalExit,
	};
}

import type { ChildProcess, SpawnOptions } from "node:child_process";

import type { RunState } from "../run/state-machine";
import type { TerminateActorProcessOptions, TerminateActorProcessResult } from "./termination";

export type ActorId = string;
export type ThreadName = string;

export interface ActorTerminationPolicy extends TerminateActorProcessOptions {}

export interface ActorSpawnRequest {
	actorId: ActorId;
	thread: ThreadName;
	command: string;
	args: string[];
	cwd: string;
	env?: NodeJS.ProcessEnv;
	stdio?: SpawnOptions["stdio"];
	termination?: Partial<ActorTerminationPolicy>;
}

export interface ActorSnapshot {
	actorId: ActorId;
	thread: ThreadName;
	pid: number | undefined;
	state: RunState;
	startedAt: number;
	exitCode: number | null;
	exitSignal: NodeJS.Signals | null;
}

export interface ActorInstance {
	readonly actorId: ActorId;
	readonly thread: ThreadName;
	readonly child: ChildProcess;
	readonly startedAt: number;
	readonly terminationPolicy: ActorTerminationPolicy;
	getSnapshot(): ActorSnapshot;
	waitForExit(): Promise<ActorSnapshot>;
	terminate(reason: string, options?: Partial<ActorTerminationPolicy>): Promise<TerminateActorProcessResult>;
}

import type { ChildProcess } from "node:child_process";

import { transitionRunState, type ExitedRunEvent, type RunState } from "../run/state-machine";
import { terminateActorProcess, type TerminateActorProcessResult } from "./termination";
import type { ActorInstance, ActorSnapshot, ActorTerminationPolicy } from "./types";

export interface ProcessActorParams {
	actorId: string;
	thread: string;
	child: ChildProcess;
	startedAt?: number;
	terminationPolicy: ActorTerminationPolicy;
}

export class ProcessActor implements ActorInstance {
	readonly actorId: string;
	readonly thread: string;
	readonly child: ChildProcess;
	readonly startedAt: number;
	readonly terminationPolicy: ActorTerminationPolicy;

	private state: RunState;
	private exitCode: number | null = null;
	private exitSignal: NodeJS.Signals | null = null;
	private readonly exitPromise: Promise<ActorSnapshot>;
	private resolveExitPromise!: (snapshot: ActorSnapshot) => void;
	private exitResolved = false;

	constructor(params: ProcessActorParams) {
		this.actorId = params.actorId;
		this.thread = params.thread;
		this.child = params.child;
		this.startedAt = params.startedAt ?? Date.now();
		this.terminationPolicy = params.terminationPolicy;

		if (typeof this.child.pid === "number") {
			this.state = transitionRunState({ tag: "queued" }, { type: "started", pid: this.child.pid });
		} else {
			this.state = { tag: "queued" };
		}

		this.exitPromise = new Promise<ActorSnapshot>((resolve) => {
			this.resolveExitPromise = resolve;
		});

		const alreadyExited = this.getCurrentExit();
		if (alreadyExited) {
			this.recordExit(alreadyExited.exitCode, alreadyExited.exitSignal);
		} else {
			this.child.once("exit", (exitCode, exitSignal) => {
				this.recordExit(exitCode, exitSignal);
			});
		}
	}

	getSnapshot(): ActorSnapshot {
		return {
			actorId: this.actorId,
			thread: this.thread,
			pid: this.child.pid ?? undefined,
			state: this.state,
			startedAt: this.startedAt,
			exitCode: this.exitCode,
			exitSignal: this.exitSignal,
		};
	}

	async waitForExit(): Promise<ActorSnapshot> {
		if (this.state.tag === "exited") {
			return this.getSnapshot();
		}

		return this.exitPromise;
	}

	async terminate(reason: string, options?: Partial<ActorTerminationPolicy>): Promise<TerminateActorProcessResult> {
		if (this.state.tag === "queued" && typeof this.child.pid === "number") {
			this.state = transitionRunState(this.state, { type: "started", pid: this.child.pid });
		}

		if (this.state.tag === "running") {
			this.state = transitionRunState(this.state, { type: "terminationRequested", reason });
		}

		const sigtermGraceMs = options?.sigtermGraceMs ?? this.terminationPolicy.sigtermGraceMs;
		const result = await terminateActorProcess(this.child, { sigtermGraceMs });

		await this.waitForExit();
		return result;
	}

	private getCurrentExit(): { exitCode: number | null; exitSignal: NodeJS.Signals | null } | null {
		if (this.child.exitCode === null && this.child.signalCode === null) return null;
		return {
			exitCode: this.child.exitCode,
			exitSignal: this.child.signalCode,
		};
	}

	private recordExit(exitCode: number | null, exitSignal: NodeJS.Signals | null): void {
		if (this.exitResolved) return;

		this.exitCode = exitCode;
		this.exitSignal = exitSignal;

		const exitedEvent: ExitedRunEvent = { type: "exited", exitCode, signal: exitSignal };

		switch (this.state.tag) {
			case "running":
				this.state = transitionRunState(this.state, exitedEvent);
				break;
			case "terminating":
				this.state = transitionRunState(this.state, exitedEvent);
				break;
			case "queued":
			case "exited":
				this.state = { tag: "exited", exitCode, signal: exitSignal };
				break;
		}

		this.exitResolved = true;
		this.resolveExitPromise(this.getSnapshot());
	}
}

import type { ActorBackend } from "../backends/actor-backend";

import type { TerminateActorProcessResult } from "./termination";
import type { ActorId, ActorInstance, ActorSpawnRequest, ThreadName } from "./types";

export interface ThreadTerminationItem {
	actorId: ActorId;
	result: TerminateActorProcessResult;
}

/**
 * Coordinates actors by thread so each thread can be supervised independently.
 *
 * This is intentionally self-contained and not wired into `index.ts` yet.
 */
export class ThreadActorSupervisor {
	constructor(private readonly backend: ActorBackend) {}

	startActor(request: ActorSpawnRequest): Promise<ActorInstance> {
		return this.backend.spawnActor(request);
	}

	listThreadActors(thread: ThreadName): readonly ActorInstance[] {
		return this.backend.listActorsForThread(thread);
	}

	async terminateThread(thread: ThreadName, reason: string): Promise<ThreadTerminationItem[]> {
		const actors = this.backend.listActorsForThread(thread);
		const terminationResults = await Promise.all(
			actors.map(async (actor) => ({
				actorId: actor.actorId,
				result: await this.backend.terminateActor(actor.actorId, reason),
			})),
		);

		return terminationResults;
	}

	removeActor(actorId: ActorId): boolean {
		return this.backend.removeActor(actorId);
	}
}

import type { TerminateActorProcessResult } from "../actors/termination";
import type { ActorId, ActorInstance, ActorSpawnRequest, ThreadName } from "../actors/types";

export interface ActorBackend {
	spawnActor(request: ActorSpawnRequest): Promise<ActorInstance>;
	getActor(actorId: ActorId): ActorInstance | undefined;
	listActors(): readonly ActorInstance[];
	listActorsForThread(thread: ThreadName): readonly ActorInstance[];
	terminateActor(actorId: ActorId, reason: string): Promise<TerminateActorProcessResult>;
	removeActor(actorId: ActorId): boolean;
}

export class ActorAlreadyExistsError extends Error {
	constructor(actorId: ActorId) {
		super(`Actor '${actorId}' already exists`);
		this.name = "ActorAlreadyExistsError";
	}
}

export class ActorNotFoundError extends Error {
	constructor(actorId: ActorId) {
		super(`Actor '${actorId}' was not found`);
		this.name = "ActorNotFoundError";
	}
}

import { spawn } from "node:child_process";

import { ProcessActor } from "../actors/process-actor";
import type { TerminateActorProcessResult } from "../actors/termination";
import type { ActorBackend } from "./actor-backend";
import { ActorAlreadyExistsError, ActorNotFoundError } from "./actor-backend";
import type { ActorId, ActorInstance, ActorSpawnRequest, ThreadName } from "../actors/types";

export interface ProcessActorBackendOptions {
	defaultSigtermGraceMs?: number;
}

export class ProcessActorBackend implements ActorBackend {
	private readonly actors = new Map<ActorId, ProcessActor>();
	private readonly actorsByThread = new Map<ThreadName, Set<ActorId>>();
	private readonly defaultSigtermGraceMs: number;

	constructor(options: ProcessActorBackendOptions = {}) {
		this.defaultSigtermGraceMs = options.defaultSigtermGraceMs ?? 5_000;
	}

	async spawnActor(request: ActorSpawnRequest): Promise<ActorInstance> {
		if (this.actors.has(request.actorId)) {
			throw new ActorAlreadyExistsError(request.actorId);
		}

		const child = spawn(request.command, request.args, {
			cwd: request.cwd,
			env: request.env,
			stdio: request.stdio ?? "pipe",
			shell: false,
		});

		const actor = new ProcessActor({
			actorId: request.actorId,
			thread: request.thread,
			child,
			terminationPolicy: {
				sigtermGraceMs: request.termination?.sigtermGraceMs ?? this.defaultSigtermGraceMs,
			},
		});

		this.actors.set(request.actorId, actor);

		let threadSet = this.actorsByThread.get(request.thread);
		if (!threadSet) {
			threadSet = new Set<ActorId>();
			this.actorsByThread.set(request.thread, threadSet);
		}
		threadSet.add(request.actorId);

		return actor;
	}

	getActor(actorId: ActorId): ActorInstance | undefined {
		return this.actors.get(actorId);
	}

	listActors(): readonly ActorInstance[] {
		return [...this.actors.values()];
	}

	listActorsForThread(thread: ThreadName): readonly ActorInstance[] {
		const actorIds = this.actorsByThread.get(thread);
		if (!actorIds) return [];

		const actors: ActorInstance[] = [];
		for (const actorId of actorIds) {
			const actor = this.actors.get(actorId);
			if (actor) actors.push(actor);
		}
		return actors;
	}

	async terminateActor(actorId: ActorId, reason: string): Promise<TerminateActorProcessResult> {
		const actor = this.actors.get(actorId);
		if (!actor) {
			throw new ActorNotFoundError(actorId);
		}

		return actor.terminate(reason);
	}

	removeActor(actorId: ActorId): boolean {
		const actor = this.actors.get(actorId);
		if (!actor) return false;

		this.actors.delete(actorId);

		const threadSet = this.actorsByThread.get(actor.thread);
		if (threadSet) {
			threadSet.delete(actorId);
			if (threadSet.size === 0) {
				this.actorsByThread.delete(actor.thread);
			}
		}

		return true;
	}
}

export interface TextPart {
	type: "text";
	text: string;
}

export interface ToolCallPart {
	type: "toolCall";
	name: string;
	arguments: Record<string, unknown>;
}

export interface UnknownPart {
	type: string;
	[key: string]: unknown;
}

export type EpisodeContentPart = TextPart | ToolCallPart | UnknownPart;

export interface AssistantEpisodeMessage {
	role: "assistant";
	content: readonly EpisodeContentPart[];
}

export interface ToolResultEpisodeMessage {
	role: "toolResult";
	toolName?: string;
	isError?: boolean;
	content: readonly EpisodeContentPart[];
}

export interface OtherEpisodeMessage {
	role: string;
	content?: readonly EpisodeContentPart[];
	[key: string]: unknown;
}

export type EpisodeMessage = AssistantEpisodeMessage | ToolResultEpisodeMessage | OtherEpisodeMessage;

function summarizeInline(text: string, maxChars: number): string {
	const normalized = text.replace(/\s+/g, " ").trim();
	if (!normalized) return "";
	if (normalized.length <= maxChars) return normalized;
	return `${normalized.slice(0, Math.max(0, maxChars - 1))}…`;
}

function isTextPart(part: EpisodeContentPart): part is TextPart {
	return part.type === "text" && typeof part.text === "string";
}

function isToolCallPart(part: EpisodeContentPart): part is ToolCallPart {
	return part.type === "toolCall" && typeof part.name === "string";
}

function summarizeToolCall(part: ToolCallPart): string {
	if (part.name === "bash") {
		const command = typeof part.arguments.command === "string" ? part.arguments.command : "";
		return `bash ${summarizeInline(command, 140) || "(no command)"}`;
	}

	const serializedArguments = JSON.stringify(part.arguments);
	return `${part.name} ${summarizeInline(serializedArguments, 140)}`.trim();
}

function summarizeToolResult(message: ToolResultEpisodeMessage): string {
	const toolName = message.toolName?.trim() || "tool";
	const rawText = message.content
		.filter(isTextPart)
		.map((part) => part.text)
		.join("\n");
	const summary = summarizeInline(rawText, 200) || "(no textual output)";
	const status = message.isError ? "error" : "ok";
	return `${toolName} (${status}): ${summary}`;
}

function collectAssistantText(message: AssistantEpisodeMessage): string {
	return message.content
		.filter(isTextPart)
		.map((part) => part.text)
		.join("\n")
		.trim();
}

function isAssistantMessage(message: EpisodeMessage): message is AssistantEpisodeMessage {
	return message.role === "assistant" && Array.isArray(message.content);
}

function isToolResultMessage(message: EpisodeMessage): message is ToolResultEpisodeMessage {
	return message.role === "toolResult" && Array.isArray(message.content);
}

export function buildEpisode(messages: readonly EpisodeMessage[]): string {
	const toolCallLines: string[] = [];
	const toolResultLines: string[] = [];
	const assistantBlocks: string[] = [];

	for (const message of messages) {
		if (isAssistantMessage(message)) {
			for (const part of message.content) {
				if (isToolCallPart(part)) {
					toolCallLines.push(summarizeToolCall(part));
				}
			}

			const assistantText = collectAssistantText(message);
			if (assistantText) {
				assistantBlocks.push(assistantText);
			}
			continue;
		}

		if (isToolResultMessage(message)) {
			toolResultLines.push(summarizeToolResult(message));
		}
	}

	const sections: string[] = [];

	if (toolCallLines.length > 0) {
		sections.push("TOOL CALLS:");
		for (const line of toolCallLines) {
			sections.push(`- ${line}`);
		}
	}

	if (toolResultLines.length > 0) {
		if (sections.length > 0) sections.push("");
		sections.push("TOOL RESULTS:");
		for (const line of toolResultLines) {
			sections.push(`- ${line}`);
		}
	}

	if (assistantBlocks.length > 0) {
		if (sections.length > 0) sections.push("");
		sections.push("THREAD RESPONSE:");
		sections.push(assistantBlocks.join("\n\n"));
	}

	return sections.join("\n") || "(no output)";
}

export type RunTerminationReason =
	| "abort"
	| "timeout"
	| "shutdown"
	| "error"
	| "completed"
	| (string & {});

export interface QueuedRunState {
	tag: "queued";
}

export interface RunningRunState {
	tag: "running";
	pid: number;
}

export interface TerminatingRunState {
	tag: "terminating";
	pid: number;
	reason: RunTerminationReason;
}

export interface ExitedRunState {
	tag: "exited";
	pid?: number | null;
	exitCode: number | null;
	signal: NodeJS.Signals | null;
	requestedTerminationReason?: RunTerminationReason;
}

export type RunState = QueuedRunState | RunningRunState | TerminatingRunState | ExitedRunState;

export interface RunStartedEvent {
	type: "started";
	pid: number;
}

export interface RunTerminationRequestedEvent {
	type: "terminationRequested";
	reason: RunTerminationReason;
}

export interface RunExitedEvent {
	type: "exited";
	exitCode: number | null;
	signal: NodeJS.Signals | null;
}

export type RunEvent = RunStartedEvent | RunTerminationRequestedEvent | RunExitedEvent;

export type StartedRunEvent = RunStartedEvent;
export type TerminationRequestedRunEvent = RunTerminationRequestedEvent;
export type ExitedRunEvent = RunExitedEvent;

export type RunEventByStateTag = {
	queued: RunStartedEvent;
	running: RunTerminationRequestedEvent | RunExitedEvent;
	terminating: RunExitedEvent;
	exited: never;
};

export type RunEventForState<TState extends RunState> = RunEventByStateTag[TState["tag"]];

export type NextRunState<
	TState extends RunState,
	TEvent extends RunEventForState<TState>,
> = TState extends QueuedRunState
	? TEvent extends RunStartedEvent
		? RunningRunState
		: never
	: TState extends RunningRunState
		? TEvent extends RunTerminationRequestedEvent
			? TerminatingRunState
			: TEvent extends RunExitedEvent
				? ExitedRunState
				: never
		: TState extends TerminatingRunState
			? TEvent extends RunExitedEvent
				? ExitedRunState
				: never
			: never;

export const INITIAL_RUN_STATE: QueuedRunState = { tag: "queued" };

export function isTerminalRunState(state: RunState): state is ExitedRunState {
	return state.tag === "exited";
}

export function canTransition<TState extends RunState>(
	state: TState,
	event: RunEvent,
): event is RunEventForState<TState> {
	switch (state.tag) {
		case "queued":
			return event.type === "started";
		case "running":
			return event.type === "terminationRequested" || event.type === "exited";
		case "terminating":
			return event.type === "exited";
		case "exited":
			return false;
	}
}

function invalidTransition<TState extends RunState>(state: TState, _event: RunEvent): TState {
	return state;
}

export function transitionRunState<
	TState extends RunState,
	TEvent extends RunEventForState<TState>,
>(state: TState, event: TEvent): NextRunState<TState, TEvent>;
export function transitionRunState(state: RunState, event: RunEvent): RunState {
	switch (state.tag) {
		case "queued": {
			if (event.type !== "started") return invalidTransition(state, event);
			return {
				tag: "running",
				pid: event.pid,
			};
		}
		case "running": {
			if (event.type === "terminationRequested") {
				return {
					tag: "terminating",
					pid: state.pid,
					reason: event.reason,
				};
			}
			if (event.type === "exited") {
				return {
					tag: "exited",
					pid: state.pid,
					exitCode: event.exitCode,
					signal: event.signal,
				};
			}
			return invalidTransition(state, event);
		}
		case "terminating": {
			if (event.type !== "exited") return invalidTransition(state, event);
			return {
				tag: "exited",
				pid: state.pid,
				exitCode: event.exitCode,
				signal: event.signal,
				requestedTerminationReason: state.reason,
			};
		}
		case "exited":
			return invalidTransition(state, event);
	}
}
